# ArgumentCompleter — auto-complétion des paramètres
function Set-AppEnv {
    param(
        [ArgumentCompleter({
            param($cmd, $param, $word, $ast, $bound)
            @('dev','staging','prod','test') | Where-Object { $_ -like "$word*" }
        })]
        [string]$Environment
    )
    Write-Host "Env : $Environment"
}
# Appuyer Tab après Set-AppEnv -Environment donne dev, staging, prod, test

