}

# [TransformAttribute] — transformation de paramètre
class PathTransform : System.Management.Automation.ArgumentTransformationAttribute {
    [object] Transform([System.Management.Automation.EngineIntrinsics]$context, [object]$input) {
        if ($input -is [string]) {
            return [System.IO.Path]::GetFullPath($input)
        }
        return $input
    }
}

function Read-Config {
    param(
        [PathTransform()]
        [string]$Path
    )
    Write-Host "Chemin absolu : $Path"
}
