function Measure-Pipeline {
    [CmdletBinding()]
    param(
        [Parameter(ValueFromPipeline = $true)]
        [object]$InputObject,

        [scriptblock]$Transform = { $_ }
    )

    begin {
        $count = 0
        $sum   = 0
        $start = [datetime]::UtcNow
        Write-Verbose "Démarrage du pipeline"
    }

    process {
        $count++
        $transformed = $InputObject | ForEach-Object $Transform
        $sum += $transformed
        $transformed  # émettre dans le pipeline
    }

    end {
        $elapsed = ([datetime]::UtcNow - $start).TotalMilliseconds
        Write-Verbose "$count objets traités en $($elapsed)ms"

        # Émettre des stats en verbose seulement
        if ($count -gt 0) {
            Write-Verbose "Somme: $sum  Moy: $([math]::Round($sum/$count,2))"
        }
    }
}

1..10 | Measure-Pipeline -Transform { $_ * $_ } -Verbose
