function Select-Top {
    [CmdletBinding()]
    param(
        [Parameter(ValueFromPipeline=$true)]
        [object]$InputObject,
        [int]$N = 5
    )
    begin   { $total = 0; $passed = 0 }
    process {
        $total++
        if ($passed -lt $N) {
            $passed++
            $InputObject
        }
    }
    end     { Write-Verbose "$total objets reçus, $passed passés" }
}

1..10 | Select-Top -N 3 -Verbose
